1 +#!/bin/bash
2 +
3 +# Configuration
4 +LOG_FILE="/tmp/tmole.log"
5 +ENV_FILE="../.env"
6 +TM_PORT=3000
7 +TM_KEYWORD="https://.*\.tunnelmole\.net"
8 +TMOLE_RUNNING=$(pgrep -f "tmole $TM_PORT")
9 +
10 +# Clean exit function
11 +cleanup() {
12 +  if [ "$OWNED_PID" = true ]; then
13 +    echo -e "\nStopping Tunnelmole (PID: $TMOLE_PID)..."
14 +    kill "$TMOLE_PID" 2>/dev/null
15 +    wait "$TMOLE_PID" 2>/dev/null
16 +  fi
17 +  exit 0
18 +}
19 +
20 +trap cleanup SIGINT SIGTERM
21 +
22 +# Function to extract URL from log
23 +extract_url_from_log() {
24 +  grep -oE "$TM_KEYWORD" "$LOG_FILE" | head -n 1
25 +}
26 +
27 +# If tmole is already running
28 +if [ -n "$TMOLE_RUNNING" ]; then
29 +  echo "Tunnelmole already running (PID: $TMOLE_RUNNING), reusing..."
30 +  TUNNEL_URL=$(extract_url_from_log)
31 +  OWNED_PID=false
32 +else
33 +  echo "Starting a new Tunnelmole session..."
34 +  rm -f "$LOG_FILE"
35 +  tmole $TM_PORT > "$LOG_FILE" 2>&1 &
36 +  TMOLE_PID=$!
37 +  OWNED_PID=true
38 +
39 +  # Wait for URL or error
40 +  echo "Waiting for tmole to initialize..."
41 +  for i in {1..20}; do
42 +    if grep -q "$TM_KEYWORD" "$LOG_FILE"; then
43 +      TUNNEL_URL=$(extract_url_from_log)
44 +      break
45 +    fi
46 +    if grep -q "limited to 10 tunnels per hour" "$LOG_FILE"; then
47 +      echo "❌ Rate limit hit: You've used your 10 free tunnels/hour. Sign up at:"
48 +      echo "👉 https://dashboard.tunnelmole.com/upgrade/run-more-tunnels-faster"
49 +      cleanup
50 +    fi
51 +    sleep 0.5
52 +  done
53 +fi
54 +
55 +# Check that we actually got a URL
56 +if [ -z "$TUNNEL_URL" ]; then
57 +  echo "❌ Failed to extract Tunnelmole URL."
58 +  cleanup
59 +fi
60 +
61 +# Update env file
62 +if [ ! -f "$ENV_FILE" ]; then
63 +  echo "⚠️  $ENV_FILE not found. Creating new file."
64 +  touch "$ENV_FILE"
65 +fi
66 +
67 +if grep -q '^GOOGLE_WEBHOOK_URL=' "$ENV_FILE"; then
68 +  sed -i '' -E "s|^GOOGLE_WEBHOOK_URL=.*|GOOGLE_WEBHOOK_URL=$TUNNEL_URL|" "$ENV_FILE"
69 +else
70 +  echo "GOOGLE_WEBHOOK_URL=$TUNNEL_URL" >> "$ENV_FILE"
71 +fi
72 +
73 +echo "✅ Updated GOOGLE_WEBHOOK_URL in $ENV_FILE to $TUNNEL_URL"
74 +echo "Tunnelmole is running. Press Ctrl+C to stop."
75 +
